#include "hall_effect.h"
#include <Arduino.h>
static int _val=0;static bool _magnet=false;static unsigned long _l=0;
void hall_setup(){Serial.println("[hall] OK");}
void hall_loop(){if(millis()-_l<100)return;_l=millis();_val=hallRead();_magnet=abs(_val)>30;}
int hall_get_value(){return _val;}
bool hall_magnet_present(){return _magnet;}
